class Solution:
    def isPossible(self, n, edges):
        edge_set = set()
        deg = [0] * (n + 1)
        for a, b in edges:
            edge_set.add((min(a, b), max(a, b)))
            deg[a] += 1
            deg[b] += 1
        if all(deg[i] % 2 == 0 for i in range(1, n + 1)):
            return True
        candidates = []
        for a in range(1, n + 1):
            for b in range(a + 1, n + 1):
                if (a, b) not in edge_set:
                    candidates.append((a, b))
        for (a, b) in candidates:
            d = deg[:]
            d[a] += 1
            d[b] += 1
            if all(d[i] % 2 == 0 for i in range(1, n + 1)):
                return True
        m = len(candidates)
        for i in range(m):
            a1, b1 = candidates[i]
            for j in range(i + 1, m):
                a2, b2 = candidates[j]
                d = deg[:]
                d[a1] += 1
                d[b1] += 1
                d[a2] += 1
                d[b2] += 1
                if all(d[k] % 2 == 0 for k in range(1, n + 1)):
                    return True
        return False

