class Solution:
    def isPossible(self, n, edges):
        adj = [set() for _ in range(n + 1)]
        deg = [0] * (n + 1)
        for a, b in edges:
            adj[a].add(b)
            adj[b].add(a)
            deg[a] += 1
            deg[b] += 1
        odd = [i for i in range(1, n + 1) if deg[i] % 2 == 1]
        if len(odd) == 0:
            return True
        if len(odd) == 2:
            u, v = odd
            if v not in adj[u]:
                return True
            for w in range(1, n + 1):
                if w != u and w != v and w not in adj[u] and w not in adj[v]:
                    return True
            return False
        if len(odd) == 4:
            a, b, c, d = odd
            pairings = [((a, b), (c, d)), ((a, c), (b, d)), ((a, d), (b, c))]
            for (x1, y1), (x2, y2) in pairings:
                if y1 not in adj[x1] and y2 not in adj[x2]:
                    return True
            return False
        return False

