var isPossible = function(n, edges) {
    const adj = Array.from({ length: n + 1 }, () => new Set());
    const deg = new Array(n + 1).fill(0);
    for (const [a, b] of edges) {
        adj[a].add(b);
        adj[b].add(a);
        deg[a]++;
        deg[b]++;
    }
    const odd = [];
    for (let i = 1; i <= n; i++) if (deg[i] % 2 === 1) odd.push(i);
    if (odd.length === 0) return true;
    if (odd.length === 2) {
        const [u, v] = odd;
        if (!adj[u].has(v)) return true;
        for (let w = 1; w <= n; w++) {
            if (w !== u && w !== v && !adj[u].has(w) && !adj[v].has(w)) return true;
        }
        return false;
    }
    if (odd.length === 4) {
        const [a, b, c, d] = odd;
        const pairings = [[[a, b], [c, d]], [[a, c], [b, d]], [[a, d], [b, c]]];
        for (const [[x1, y1], [x2, y2]] of pairings) {
            if (!adj[x1].has(y1) && !adj[x2].has(y2)) return true;
        }
        return false;
    }
    return false;
};
